/**
 * Thrash Detector — UserPromptSubmit hook
 *
 * Source: usage analytics — recurring edit→format→revert→re-edit and
 * edit→test-fail→undo→re-edit loops that burn 10+ turns on the same
 * file. Catches the "same-file repeatedly" signal early and suggests a
 * different approach.
 *
 * Reads `.claude/state/edit-history.jsonl` (maintained by
 * posttool/write/edit-history-tracker) and computes per-file edit
 * counts in the rolling window. If any single file has been edited
 * THRASH_THRESHOLD times in WINDOW_ENTRIES most recent events, inject
 * an advisory additionalContext.
 *
 * Also truncates the history file to MAX_ENTRIES on read, keeping
 * the JSONL bounded without a separate sweeper.
 */

import { existsSync, readFileSync, writeFileSync } from 'node:fs';
import { basename } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { getEditHistoryPath } from '../posttool/write/edit-history-tracker.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'prompt/thrash-detector';

// If any single file appears >= THRASH_THRESHOLD times in the last
// WINDOW_ENTRIES edit events, flag as thrash.
const THRASH_THRESHOLD = 3;
const WINDOW_ENTRIES = 10;

// Hard cap on the JSONL size — trimmed on every invocation.
const MAX_ENTRIES = 50;

interface EditEntry {
  t: number;
  f: string;
  tool?: string;
}

/**
 * Read recent edit events (up to MAX_ENTRIES). Truncates the file
 * in-place if it exceeded the cap.
 */
function readAndTrimHistory(path: string): EditEntry[] {
  if (!existsSync(path)) return [];
  let content: string;
  try {
    content = readFileSync(path, 'utf8');
  } catch {
    return [];
  }
  const entries: EditEntry[] = [];
  for (const line of content.split('\n')) {
    if (!line.trim()) continue;
    try {
      const parsed = JSON.parse(line) as EditEntry;
      if (parsed.f && typeof parsed.t === 'number') entries.push(parsed);
    } catch {
      // skip malformed lines
    }
  }
  if (entries.length > MAX_ENTRIES) {
    const trimmed = entries.slice(-MAX_ENTRIES);
    try {
      writeFileSync(path, trimmed.map(e => JSON.stringify(e)).join('\n') + '\n', 'utf8');
    } catch {
      // best-effort
    }
    return trimmed;
  }
  return entries;
}

/**
 * Analyze the last WINDOW_ENTRIES events and return files that hit the
 * thrash threshold.
 */
function findThrashingFiles(entries: EditEntry[]): Map<string, number> {
  const window = entries.slice(-WINDOW_ENTRIES);
  const counts = new Map<string, number>();
  for (const e of window) {
    counts.set(e.f, (counts.get(e.f) || 0) + 1);
  }
  const thrashing = new Map<string, number>();
  for (const [file, count] of counts.entries()) {
    if (count >= THRASH_THRESHOLD) thrashing.set(file, count);
  }
  return thrashing;
}

export function thrashDetector(_input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  const path = getEditHistoryPath(ctx.projectDir);
  const entries = readAndTrimHistory(path);
  if (entries.length < THRASH_THRESHOLD) return outputSilentSuccess();

  const thrashing = findThrashingFiles(entries);
  if (thrashing.size === 0) return outputSilentSuccess();

  const lines = Array.from(thrashing.entries())
    .sort((a, b) => b[1] - a[1])
    .map(([file, count]) => `  - ${basename(file)}: ${count} edits in the last ${WINDOW_ENTRIES} events`);

  ctx.log(HOOK_NAME, `Thrash detected on ${thrashing.size} file(s)`);

  return {
    continue: true,
    hookSpecificOutput: {
      additionalContext:
        `[thrash-detector] You've edited the same file(s) repeatedly in the last ${WINDOW_ENTRIES} edit events:\n${lines.join('\n')}\n` +
        `This pattern often signals a test↔edit or formatter↔edit loop. Consider a different approach, read the file once more end-to-end, or ask the user for guidance.`,
    },
  };
}

// Testing exports
export {
  readAndTrimHistory,
  findThrashingFiles,
  THRASH_THRESHOLD,
  WINDOW_ENTRIES,
  MAX_ENTRIES,
};
